export const OUTPUT_FORMATS = ['PNG', 'JPG', 'WEBP']

const RASTER_FORMATS = ['PNG', 'JPG', 'JPEG', 'WEBP']

export const isRasterExportSetting = exportSetting =>
  RASTER_FORMATS.indexOf((exportSetting.format || '').toUpperCase()) > -1

export const getRasterExportSettings = exportSettings =>
  (exportSettings || []).filter(isRasterExportSetting)

export const getScale = exportSetting => {
  if (exportSetting.constraint && exportSetting.constraint.value) {
    return exportSetting.constraint.value
  }
  const match = /@(\d+)x/.exec(exportSetting.fileName || '')
  return match ? Number(match[1]) : 1
}

export const getCleanName = exportSetting => {
  const fileName = exportSetting.fileName || exportSetting.name || 'slice'
  const name = fileName
    .split('/')
    .pop()
    .replace(/\.[^.]+$/, '')
    .replace(/[-_]?@\d+x$/, '')
    .replace(/[-_]$/, '')
  return name || 'slice'
}

export const groupExportSettings = exportSettings => {
  const grouped = {}
  getRasterExportSettings(exportSettings).forEach((exportSetting, index) => {
    const name = getCleanName(exportSetting)
    const key = `${exportSetting.id || 'unknown'}-${name}`
    if (!grouped[key]) {
      grouped[key] = {
        key,
        name,
        id: exportSetting.id,
        exportSettings: [],
        firstIndex: index
      }
    }
    grouped[key].exportSettings.push(exportSetting)
  })

  return Object.keys(grouped).map(key => {
    const group = grouped[key]
    const sourceSetting = group.exportSettings
      .slice()
      .sort((a, b) => getScale(b) - getScale(a))[0]
    return {
      ...group,
      sourceSetting,
      sourceScale: getScale(sourceSetting)
    }
  })
}

export const getMimeType = format => {
  switch (format) {
    case 'JPG':
      return 'image/jpeg'
    case 'WEBP':
      return 'image/webp'
    default:
      return 'image/png'
  }
}

const loadImageElement = url =>
  new Promise((resolve, reject) => {
    const image = new Image()
    const timer = setTimeout(() => {
      image.onload = null
      image.onerror = null
      reject(new Error(`图片加载超时：${url}`))
    }, 15000)
    image.onerror = () => {
      clearTimeout(timer)
      reject(new Error(`图片加载失败：${url}`))
    }
    image.onload = () => {
      clearTimeout(timer)
      resolve(image)
    }
    image.src = url
  })

export const loadImage = async url => {
  try {
    const response = await fetch(url)
    if (!response.ok) {
      throw new Error(`${response.status} ${response.statusText}`)
    }
    const blob = await response.blob()
    const objectUrl = URL.createObjectURL(blob)
    try {
      return await loadImageElement(objectUrl)
    } finally {
      URL.revokeObjectURL(objectUrl)
    }
  } catch (error) {
    const message = error && error.message ? error.message : String(error)
    throw new Error(`图片读取失败：${url}。请用 http 服务打开 HTML，不要直接双击打开文件。${message}`)
  }
}

export const canvasToBlob = (image, width, height, format) =>
  new Promise((resolve, reject) => {
    const canvas = document.createElement('canvas')
    canvas.width = width
    canvas.height = height
    const context = canvas.getContext('2d')
    try {
      context.clearRect(0, 0, width, height)
      context.drawImage(image, 0, 0, width, height)
      canvas.toBlob(blob => {
        if (!blob) {
          reject(new Error(`图片转换失败：${width}px x ${height}px ${format}`))
          return
        }
        resolve(blob)
      }, getMimeType(format), format === 'JPG' ? 0.92 : undefined)
    } catch (error) {
      reject(error)
    }
  })

export const getExtension = format => format.toLowerCase().replace('jpeg', 'jpg')

export const getOutputName = (baseName, density, format, platform) => {
  const extension = getExtension(format)
  if (platform === 'android') {
    return `${baseName}-${density.key}.${extension}`
  }
  return density.scale === 1 ? `${baseName}.${extension}` : `${baseName}@${density.key}.${extension}`
}

export const getBaseSize = (image, sourceScale) => ({
  width: Math.round(image.naturalWidth / sourceScale),
  height: Math.round(image.naturalHeight / sourceScale)
})

export const addUniqueZipFile = (zip, fileName, blob, usedNames) => {
  if (!usedNames[fileName]) {
    usedNames[fileName] = 1
    zip.file(fileName, blob)
    return
  }

  const pieces = fileName.split('.')
  const extension = pieces.pop()
  const stem = pieces.join('.')
  let index = usedNames[fileName]
  let nextName = `${stem}-${index}.${extension}`
  while (usedNames[nextName]) {
    index += 1
    nextName = `${stem}-${index}.${extension}`
  }
  usedNames[fileName] = index + 1
  usedNames[nextName] = 1
  zip.file(nextName, blob)
}
